import React, { useState, useEffect, useCallback } from 'react';
import { Card, Form, Button, Table, Badge, Modal } from 'react-bootstrap';
import { Search, Eye, Download, History, Edit2, Trash2 } from 'lucide-react';
import { toast } from 'react-toastify';
import { searchDocuments, downloadDocument } from '../api';
import api from '../api';
import DocumentPreview from './DocumentPreview';
import VersionHistory from './VersionHistory';
import './DocumentRetrieval.css';

const DocumentRetrieval = () => {
  const [searchCriteria, setSearchCriteria] = useState({
    employeeId: '',
    employeeName: '',
    store: '',
    documentType: '',
    expiryDateFrom: '',
    expiryDateTo: ''
  });
  const [filteredDocuments, setFilteredDocuments] = useState([]);
  const [sortConfig, setSortConfig] = useState({ key: null, direction: 'asc' });
  
  // Preview modal
  const [previewDocument, setPreviewDocument] = useState(null);
  const [showPreview, setShowPreview] = useState(false);
  
  // Version history modal
  const [showVersionHistory, setShowVersionHistory] = useState(false);
  const [selectedDocumentForVersion, setSelectedDocumentForVersion] = useState(null);
  
  // Edit metadata modal
  const [showEditModal, setShowEditModal] = useState(false);
  const [editingDocument, setEditingDocument] = useState(null);
  const [editFormData, setEditFormData] = useState({
    documentType: '',
    issueDate: '',
    expiryDate: '',
    remarks: ''
  });
  
  // Delete confirmation modal
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [documentToDelete, setDocumentToDelete] = useState(null);

  const documentTypes = [
    'ID Proof',
    'Driving License',
    'Medical Certificate',
    'Training Certificate',
    'Employment Contract',
    'Educational Certificate',
    'Address Proof',
    'Police Verification'
  ];

  const stores = Array.from({ length: 20 }, (_, i) => `Store ${i + 1}`);

  const loadDocuments = useCallback(async () => {
    try {
      const response = await searchDocuments({});
      if (response.data && response.data.data) {
        const docs = response.data.data.map(doc => ({
          ...doc,
          status: getStatusColor(doc.expiryDate)
        }));
        setFilteredDocuments(docs);
      }
    } catch (error) {
      console.error('Error loading documents:', error);
      setFilteredDocuments([]);
    }
  }, []);

  useEffect(() => {
    loadDocuments();
  }, [loadDocuments]);

  const getStatusBadge = (status) => {
    const badges = {
      valid: { variant: 'success', text: 'Valid' },
      expiring: { variant: 'warning', text: 'Expiring Soon' },
      expired: { variant: 'danger', text: 'Expired' }
    };
    return badges[status] || badges.valid;
  };

  const getStatusColor = (expiryDate) => {
    if (!expiryDate) return 'valid';
    const today = new Date();
    const expiry = new Date(expiryDate);
    const daysUntilExpiry = Math.floor((expiry - today) / (1000 * 60 * 60 * 24));
    
    if (daysUntilExpiry < 0) return 'expired';
    if (daysUntilExpiry <= 30) return 'expiring';
    return 'valid';
  };

  const handleSearch = async () => {
    try {
      const response = await searchDocuments(searchCriteria);
      if (response.data && response.data.data) {
        const results = response.data.data.map(doc => ({
          ...doc,
          status: getStatusColor(doc.expiryDate)
        }));
        setFilteredDocuments(results);
        toast.info(`Found ${results.length} document(s)`);
      }
    } catch (error) {
      toast.error('Error searching documents');
      console.error(error);
    }
  };

  const handleReset = () => {
    setSearchCriteria({
      employeeId: '',
      employeeName: '',
      store: '',
      documentType: '',
      expiryDateFrom: '',
      expiryDateTo: ''
    });
    loadDocuments();
  };

  const handleSort = (key) => {
    let direction = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });

    const sorted = [...filteredDocuments].sort((a, b) => {
      if (a[key] < b[key]) return direction === 'asc' ? -1 : 1;
      if (a[key] > b[key]) return direction === 'asc' ? 1 : -1;
      return 0;
    });

    setFilteredDocuments(sorted);
  };

  const handleView = (doc) => {
    setPreviewDocument(doc);
    setShowPreview(true);
  };

  const handleDownload = async (doc) => {
    try {
      const docId = doc.id.replace('DOC', '');
      const response = await downloadDocument(docId);
      const blob = new Blob([response.data]);
      const url = URL.createObjectURL(blob);
      const link = window.document.createElement('a');
      link.href = url;
      link.download = doc.fileName || 'document';
      window.document.body.appendChild(link);
      link.click();
      window.document.body.removeChild(link);
      URL.revokeObjectURL(url);
      toast.success('Document downloaded successfully');
    } catch (error) {
      toast.error('Error downloading document');
    }
  };

  const handleEditClick = (doc) => {
    setEditingDocument(doc);
    setEditFormData({
      documentType: doc.documentType,
      issueDate: doc.issueDate || '',
      expiryDate: doc.expiryDate || '',
      remarks: doc.remarks || ''
    });
    setShowEditModal(true);
  };

  const handleUpdateMetadata = async (e) => {
    e.preventDefault();
    try {
      const docId = editingDocument.id.replace('DOC', '');
      await api.put(`/documents/${docId}/metadata`, editFormData);
      toast.success('Document metadata updated successfully');
      loadDocuments();
      setShowEditModal(false);
      setEditingDocument(null);
    } catch (error) {
      toast.error('Error updating document: ' + (error.response?.data?.message || error.message));
      console.error(error);
    }
  };

  const handleDeleteClick = (doc) => {
    setDocumentToDelete(doc);
    setShowDeleteModal(true);
  };

  const confirmDelete = async () => {
    try {
      const docId = documentToDelete.id.replace('DOC', '');
      await api.delete(`/documents/${docId}`, { 
        data: { reason: 'Deleted by user' } 
      });
      toast.success('Document deleted successfully');
      loadDocuments();
      setShowDeleteModal(false);
      setDocumentToDelete(null);
    } catch (error) {
      toast.error('Error deleting document: ' + (error.response?.data?.message || error.message));
      console.error(error);
    }
  };

  return (
    <div className="document-retrieval">
      <Card className="retrieval-card">
        <Card.Header className="card-header-custom">
          <h3 className="mb-0">
            <Search className="me-2" size={24} />
            Document Retrieval & Search
          </h3>
        </Card.Header>
        <Card.Body>
          {/* Search Form */}
          <Card className="search-card mb-4">
            <Card.Body>
              <div className="row g-3">
                <div className="col-md-3">
                  <Form.Label>Employee ID</Form.Label>
                  <Form.Control
                    type="text"
                    placeholder="Enter Employee ID"
                    value={searchCriteria.employeeId}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, employeeId: e.target.value })}
                  />
                </div>
                <div className="col-md-3">
                  <Form.Label>Employee Name</Form.Label>
                  <Form.Control
                    type="text"
                    placeholder="Enter Employee Name"
                    value={searchCriteria.employeeName}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, employeeName: e.target.value })}
                  />
                </div>
                <div className="col-md-3">
                  <Form.Label>Store</Form.Label>
                  <Form.Select
                    value={searchCriteria.store}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, store: e.target.value })}
                  >
                    <option value="">All Stores</option>
                    {stores.map(store => (
                      <option key={store} value={store}>{store}</option>
                    ))}
                  </Form.Select>
                </div>
                <div className="col-md-3">
                  <Form.Label>Document Type</Form.Label>
                  <Form.Select
                    value={searchCriteria.documentType}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, documentType: e.target.value })}
                  >
                    <option value="">All Types</option>
                    {documentTypes.map(type => (
                      <option key={type} value={type}>{type}</option>
                    ))}
                  </Form.Select>
                </div>
                <div className="col-md-3">
                  <Form.Label>Expiry Date From</Form.Label>
                  <Form.Control
                    type="date"
                    value={searchCriteria.expiryDateFrom}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, expiryDateFrom: e.target.value })}
                  />
                </div>
                <div className="col-md-3">
                  <Form.Label>Expiry Date To</Form.Label>
                  <Form.Control
                    type="date"
                    value={searchCriteria.expiryDateTo}
                    onChange={(e) => setSearchCriteria({ ...searchCriteria, expiryDateTo: e.target.value })}
                  />
                </div>
              </div>
              <div className="mt-3 d-flex gap-2">
                <Button variant="primary" onClick={handleSearch}>
                  <Search className="me-2" size={18} />
                  Search
                </Button>
                <Button variant="outline-secondary" onClick={handleReset}>
                  Reset
                </Button>
              </div>
            </Card.Body>
          </Card>

          {/* Results Table */}
          <div className="table-responsive">
            <Table hover className="results-table">
              <thead>
                <tr>
                  <th onClick={() => handleSort('id')} className="sortable">
                    Document ID {sortConfig.key === 'id' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('employeeName')} className="sortable">
                    Employee Name {sortConfig.key === 'employeeName' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('store')} className="sortable">
                    Store {sortConfig.key === 'store' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('documentType')} className="sortable">
                    Document Type {sortConfig.key === 'documentType' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th onClick={() => handleSort('expiryDate')} className="sortable">
                    Expiry Date {sortConfig.key === 'expiryDate' && (sortConfig.direction === 'asc' ? '↑' : '↓')}
                  </th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredDocuments.length === 0 ? (
                  <tr>
                    <td colSpan="7" className="text-center py-5 text-muted">
                      No documents found. Try adjusting your search criteria.
                    </td>
                  </tr>
                ) : (
                  filteredDocuments.map((doc) => {
                    const status = getStatusBadge(doc.status);
                    return (
                      <tr key={doc.id}>
                        <td>{doc.id}</td>
                        <td>
                          <div>
                            <strong>{doc.employeeName}</strong>
                            <br />
                            <small className="text-muted">{doc.employeeId}</small>
                          </div>
                        </td>
                        <td>{doc.store}</td>
                        <td>{doc.documentType}</td>
                        <td>{doc.expiryDate || 'N/A'}</td>
                        <td>
                          <Badge bg={status.variant}>{status.text}</Badge>
                        </td>
                        <td>
                          <div className="action-buttons">
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => handleView(doc)}
                              className="action-btn"
                              title="View"
                            >
                              <Eye size={18} />
                            </Button>
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => handleDownload(doc)}
                              className="action-btn"
                              title="Download"
                            >
                              <Download size={18} />
                            </Button>
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => handleEditClick(doc)}
                              className="action-btn"
                              title="Edit Metadata"
                            >
                              <Edit2 size={18} />
                            </Button>
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => {
                                setSelectedDocumentForVersion(doc.id);
                                setShowVersionHistory(true);
                              }}
                              className="action-btn"
                              title="Version History"
                            >
                              <History size={18} />
                            </Button>
                            <Button
                              variant="link"
                              size="sm"
                              onClick={() => handleDeleteClick(doc)}
                              className="action-btn text-danger"
                              title="Delete"
                            >
                              <Trash2 size={18} />
                            </Button>
                          </div>
                        </td>
                      </tr>
                    );
                  })
                )}
              </tbody>
            </Table>
          </div>
        </Card.Body>
      </Card>
      
      {/* Document Preview Modal */}
      <DocumentPreview
        show={showPreview}
        onHide={() => {
          setShowPreview(false);
          setPreviewDocument(null);
        }}
        document={previewDocument}
      />

      {/* Version History Modal */}
      <Modal show={showVersionHistory} onHide={() => setShowVersionHistory(false)} size="lg" centered>
        <Modal.Header closeButton>
          <Modal.Title>
            <History className="me-2" size={20} />
            Version History
          </Modal.Title>
        </Modal.Header>
        <Modal.Body>
          {selectedDocumentForVersion && (
            <VersionHistory documentId={selectedDocumentForVersion} />
          )}
        </Modal.Body>
      </Modal>

      {/* Edit Metadata Modal */}
      <Modal show={showEditModal} onHide={() => setShowEditModal(false)} centered>
        <Modal.Header closeButton>
          <Modal.Title>
            <Edit2 className="me-2" size={20} />
            Edit Document Metadata
          </Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <Form onSubmit={handleUpdateMetadata}>
            <Form.Group className="mb-3">
              <Form.Label>Document Type</Form.Label>
              <Form.Select
                value={editFormData.documentType}
                onChange={(e) => setEditFormData({...editFormData, documentType: e.target.value})}
                required
              >
                {documentTypes.map(type => (
                  <option key={type} value={type}>{type}</option>
                ))}
              </Form.Select>
            </Form.Group>
            
            <Form.Group className="mb-3">
              <Form.Label>Issue Date</Form.Label>
              <Form.Control
                type="date"
                value={editFormData.issueDate}
                onChange={(e) => setEditFormData({...editFormData, issueDate: e.target.value})}
              />
            </Form.Group>
            
            <Form.Group className="mb-3">
              <Form.Label>Expiry Date</Form.Label>
              <Form.Control
                type="date"
                value={editFormData.expiryDate}
                onChange={(e) => setEditFormData({...editFormData, expiryDate: e.target.value})}
              />
            </Form.Group>
            
            <Form.Group className="mb-3">
              <Form.Label>Remarks</Form.Label>
              <Form.Control
                as="textarea"
                rows={3}
                value={editFormData.remarks}
                onChange={(e) => setEditFormData({...editFormData, remarks: e.target.value})}
                placeholder="Enter remarks"
              />
            </Form.Group>
            
            <div className="d-flex gap-2 justify-content-end">
              <Button variant="secondary" onClick={() => setShowEditModal(false)}>
                Cancel
              </Button>
              <Button variant="primary" type="submit">
                Update Metadata
              </Button>
            </div>
          </Form>
        </Modal.Body>
      </Modal>

      {/* Delete Confirmation Modal */}
      <Modal show={showDeleteModal} onHide={() => setShowDeleteModal(false)} centered>
        <Modal.Header closeButton>
          <Modal.Title className="text-danger">
            <Trash2 className="me-2" size={20} />
            Confirm Delete
          </Modal.Title>
        </Modal.Header>
        <Modal.Body>
          <p>Are you sure you want to delete this document?</p>
          {documentToDelete && (
            <div className="bg-light p-3 rounded">
              <strong>Document:</strong> {documentToDelete.fileName}<br />
              <strong>Employee:</strong> {documentToDelete.employeeName}<br />
              <strong>Type:</strong> {documentToDelete.documentType}
            </div>
          )}
          <div className="alert alert-warning mt-3 mb-0">
            <small>⚠️ This action cannot be undone!</small>
          </div>
        </Modal.Body>
        <Modal.Footer>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>
            Cancel
          </Button>
          <Button variant="danger" onClick={confirmDelete}>
            <Trash2 size={16} className="me-1" />
            Delete Document
          </Button>
        </Modal.Footer>
      </Modal>
    </div>
  );
};

export default DocumentRetrieval;
